contracts/storage/ESVSPStorage.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity 0.8.9;

import "../interface/IESVSP.sol";
import "../interface/IESVSP721.sol";

abstract contract ESVSPStorageV1 is IESVSP {
    struct LockPosition {
        uint256 lockedAmount; // VSP locked
        uint256 boostedAmount; // based on the `lockPeriod`
        uint256 unlockTime; // now + `lockPeriod`
    }

    uint8 public decimals;
    string public name;
    string public symbol;

    /**
     * @notice The treasury contract (will receive exit penalty collected)
     */
    address public treasury;

    /**
     * @notice NFT contract
     */
    IESVSP721 public esVSP721;

    /**
     * @notice Rewards contract
     */
    IRewards public rewards;

    /**
     * @notice Total VSP locked
     */
    uint256 public override totalLocked;

    /**
     * @notice Total boosted amount
     */
    uint256 public override totalBoosted;

    /**
     * @notice Fee paid when withdrawing. Decreases linearly as period finish approaches.
     * @dev Use 18 decimals (e.g. 0.5e18 is 50%)
     */
    uint256 public exitPenalty;

    /**
     * @notice Lock positions
     * @dev tokenId => position
     */
    mapping(uint256 => LockPosition) public positions;

    /**
     * @notice Total VSP locked by user among all his positions
     * @dev user => total locked;
     */
    mapping(address => uint256) public override locked;

    /**
     * @notice Total boosted amount by user among all his positions
     * @dev user => total boosted;
     */
    mapping(address => uint256) public override boosted;

    /**
     * @notice A checkpoint for marking number of votes from a given block
     */
    struct Checkpoint {
        uint32 fromBlock;
        uint256 votes;
    }

    /**
     * @dev A record of each accounts delegate
     */
    mapping(address => address) internal _delegates;

    /**
     * @dev A record of votes checkpoints for each account
     */
    mapping(address => Checkpoint[]) internal _checkpoints;

    Checkpoint[] internal _totalSupplyCheckpoints;

    /**
     * @notice A record of states for signing / validating signatures
     */
    mapping(address => uint256) public nonces;
}

contracts/storage/RewardsStorage.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity 0.8.9;

import "../interface/IESVSP.sol";
import "../interface/IRewards.sol";

abstract contract RewardsStorageV1 is IRewards {
    struct Reward {
        bool isBoosted; // linear distribution if false
        uint256 periodFinish; // end of a drip period
        uint256 rewardPerSecond; // distribution per second (i.e. dripAmount/dripPeriod)
        uint256 lastUpdateTime; // stores last drip time
        uint256 rewardPerTokenStored; // reward per VSP
    }

    struct UserReward {
        uint128 rewardPerTokenPaid; // reward per VSP accumulator
        uint128 claimableRewardsStored; // pending to claim
    }

    /**
     * @notice Locker contract
     */
    IESVSP public esVSP;

    /**
     * @notice Array of reward tokens
     */
    address[] public rewardTokens;

    /**
     * @notice Rewards state per token
     * @dev RewardToken => Reward
     */
    mapping(address => Reward) public rewards;

    /**
     * @notice User's rewards state per token
     * @dev User => RewardToken => UserReward
     */
    mapping(address => mapping(address => UserReward)) public rewardOf;

    /**
     * @notice Reward distributors
     * RewardToken -> distributor -> is approved to drip
     */
    mapping(address => mapping(address => bool)) public isRewardDistributor;
}

